import { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation } from "react-router-dom";
import { getaOrder } from "../../features/auth/authSlice";
import Loading from "../../utils/Loading";
import { FaUser, FaBox, FaMapMarkerAlt, FaMoneyBillWave, FaTimes } from "react-icons/fa";

const OrderDetail = () => {
  const location = useLocation();
  const orderId = location.pathname.split("/")[3];
  const dispatch = useDispatch();
  const [gallery, setGallery] = useState({ open: false, images: [], currentIndex: 0 });

  useEffect(() => {
    dispatch(getaOrder(orderId));
  }, [dispatch, orderId]);

  const order = useSelector((state) => state?.auth?.singleorder?.orders);

  if (!order) {
    return (
      <div className="flex justify-center items-center h-screen">
        <Loading />
      </div>
    );
  }

  // Open image gallery
  const openGallery = (images, index) => {
    setGallery({ open: true, images, currentIndex: index });
  };

  // Close image gallery
  const closeGallery = () => {
    setGallery({ open: false, images: [], currentIndex: 0 });
  };

  // Navigate gallery images
  const nextImage = () => {
    setGallery((prev) => ({
      ...prev,
      currentIndex: (prev.currentIndex + 1) % prev.images.length,
    }));
  };

  const prevImage = () => {
    setGallery((prev) => ({
      ...prev,
      currentIndex:
        prev.currentIndex === 0 ? prev.images.length - 1 : prev.currentIndex - 1,
    }));
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white py-12 px-4">
      <div className="max-w-4xl mx-auto p-8 bg-gray-800 shadow-xl rounded-3xl">

        {/* User Details */}
        <div className="flex items-center space-x-6 border-b pb-6">
          <FaUser className="text-4xl text-blue-400" />
          <div>
            <h2 className="text-2xl font-bold">{order.first_name} {order.last_name}</h2>
            <p className="text-gray-400">{order.email}</p>
            <p className="text-gray-400">{order.phone_number}</p>
          </div>
        </div>

        {/* Shipping Address */}
        <div className="border-b pb-6 mt-6">
          <h3 className="text-lg font-semibold flex items-center mb-2">
            <FaMapMarkerAlt className="mr-2 text-blue-400" /> Shipping Address
          </h3>
          <p className="text-gray-300">{order.address}, {order.city}, {order.country}, {order.postalCode}</p>
        </div>

        {/* Order Status & Payment */}
        <div className="flex justify-between items-center border-b pb-6 mt-6">
          <span className={`px-4 py-2 rounded-full font-semibold text-sm
            ${order.orderStatus === "pending" ? "bg-yellow-500 text-gray-900" :
              order.orderStatus === "delivered" ? "bg-green-500 text-gray-900" :
                "bg-gray-500 text-gray-100"
            }`}>
            {order.orderStatus.toUpperCase()}
          </span>

          <div className="flex items-center space-x-2">
            <FaMoneyBillWave className="text-green-400 text-xl" />
            <span className="text-xl font-bold">{order.totalPriceAfterDiscount}<span className="text-sm ml-2">ETB</span></span>
          </div>
        </div>

        {/* Order Items */}
        <div className="mt-6">
          <h3 className="text-lg font-semibold flex items-center mb-4">
            <FaBox className="mr-2 text-blue-400" /> Order Items
          </h3>

          <div className="space-y-6">
            {order.cart.map((item) => (
              <div key={item._id} className="bg-gray-700 p-6 rounded-2xl shadow-lg flex flex-col md:flex-row items-center space-x-6">

                {/* Product Images */}
                <div className="w-full md:w-1/3 flex space-x-3 overflow-x-auto p-2">
                  {item.product?.colors?.flatMap(color => color.images)?.map((img, index) => (
                    <img
                      key={index}
                      src={img.secure_url}
                      alt="Product"
                      className="w-24 h-24 object-cover rounded-xl shadow-md cursor-pointer hover:scale-105 transition-transform"
                      onClick={() => openGallery(
                        item.product?.colors?.flatMap(color => color.images)?.map(img => img.secure_url),
                        index
                      )}
                    />
                  ))}
                </div>

                {/* Product Details */}
                <div className="flex-1 text-center md:text-left">
                  <h4 className="text-2xl font-semibold">{item.product.title}</h4>
                  <p className="text-gray-300">Size: {item.size}</p>
                  <p className="text-gray-300">Quantity: {item.quantity}</p>
                  <p className="text-xl font-bold text-white">{item.price}<span className="text-sm ml-2">ETB</span></p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Gallery Modal */}
      {gallery.open && (
        <div className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-50">
          <button className="absolute top-4 right-4 text-white text-3xl" onClick={closeGallery}>
            <FaTimes />
          </button>

          <button className="absolute left-6 text-white text-3xl" onClick={prevImage}>&lt;</button>
          <img
            src={gallery.images[gallery.currentIndex]}
            alt="Gallery"
            className="max-w-3xl max-h-[80vh] rounded-xl shadow-2xl"
          />
          <button className="absolute right-6 text-white text-3xl" onClick={nextImage}>&gt;</button>
        </div>
      )}
    </div>
  );
};

export default OrderDetail;
